INSERT INTO public.event_testimonies (event_id, user_id, author_name, quote) VALUES ('df85910e-82da-4ef7-98d2-d4c827d1d0ec', '58fd426a-25bb-48c4-bc68-3a21d69553db', 'Sophie D', '« C''était vraiment cette notion d''être à la rencontre des autres et à la fois d''apprendre et aussi de revenir à quelque chose que j''ai connu avec mon grand-père. »') ON CONFLICT (event_id, user_id) DO UPDATE SET quote=EXCLUDED.quote, updated_at=now();